from collections import deque, defaultdict
class Solution:
    def numberOfEdgesAdded(self, n, edges):
        adj = defaultdict(list)
        count = 0
        for u, v, w in edges:
            visited = {u: 0}
            q = deque([u])
            while q:
                cur = q.popleft()
                for nxt, wt in adj[cur]:
                    if nxt not in visited:
                        visited[nxt] = visited[cur] ^ wt
                        q.append(nxt)
            if v in visited:
                if visited[v] == w:
                    adj[u].append((v, w))
                    adj[v].append((u, w))
                    count += 1
            else:
                adj[u].append((v, w))
                adj[v].append((u, w))
                count += 1
        return count

