class Solution:
    def numberOfEdgesAdded(self, n, edges):
        parent = list(range(n))
        potential = [0] * n
        def find(x):
            chain = []
            root = x
            while parent[root] != root:
                chain.append(root)
                root = parent[root]
            acc = 0
            par_to_root = {}
            for node in reversed(chain):
                acc ^= potential[node]
                par_to_root[node] = acc
            for node in chain:
                parent[node] = root
                potential[node] = par_to_root[node]
            return root, (par_to_root[x] if chain else 0)
        count = 0
        for u, v, w in edges:
            ru, pu = find(u)
            rv, pv = find(v)
            if ru != rv:
                parent[ru] = rv
                potential[ru] = pu ^ pv ^ w
                count += 1
            else:
                if (pu ^ pv) == w:
                    count += 1
        return count

