var numberOfEdgesAdded = function(n, edges) {
    const parent = new Array(n);
    const potential = new Array(n).fill(0);
    for (let i = 0; i < n; i++) parent[i] = i;
    function find(x) {
        const chain = [];
        let root = x;
        while (parent[root] !== root) {
            chain.push(root);
            root = parent[root];
        }
        let acc = 0;
        const parToRoot = new Map();
        for (let i = chain.length - 1; i >= 0; i--) {
            const node = chain[i];
            acc ^= potential[node];
            parToRoot.set(node, acc);
        }
        for (const node of chain) {
            parent[node] = root;
            potential[node] = parToRoot.get(node);
        }
        return [root, chain.length ? parToRoot.get(x) : 0];
    }
    let count = 0;
    for (const [u, v, w] of edges) {
        const [ru, pu] = find(u);
        const [rv, pv] = find(v);
        if (ru !== rv) {
            parent[ru] = rv;
            potential[ru] = pu ^ pv ^ w;
            count++;
        } else if ((pu ^ pv) === w) {
            count++;
        }
    }
    return count;
};
